import javax.jws.WebService;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.DocumentBuilder;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;
import org.w3c.dom.Node;
import org.w3c.dom.Element;
import java.io.ByteArrayInputStream;

@WebService(endpointInterface = "com.example.XmlProcessingService")
public class XmlProcessingServiceImpl implements XmlProcessingService {

    @Override
    public String processXML(String xml) throws Exception {
        byte[] bytes = xml.getBytes();
        ByteArrayInputStream bis = new ByteArrayInputStream(bytes);
        
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(bis);
        
        NodeList nodeList = doc.getElementsByTagName("entity");
        
        for (int i = 0; i < nodeList.getLength(); i++) {
            Node node = nodeList.item(i);
            
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                
                // Process the XML entity here...
                String entityValue = element.getTextContent();
                System.out.println("Entity value: " + entityValue);
            }
        }
        
        return "XML processed successfully";
    }
}